var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BULLY_NPC_NULL_M","text":{"KOREA":"커억…!","JPN":"ガハッ！","ENG":"Khhkkk!","TWN":"噢嗚…！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BULLY_NPC_NULL_F","text":{"KOREA":"뭐, 뭐야? 무슨 주먹 한 방에 나가떨어져?","JPN":"そ、そんな！　一発で吹っ飛ばされた！？","ENG":"W-what the hell? She knocked him out with a single punch!","TWN":"什…什麼？竟然一拳就把人打飛？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"당신도 덤빌 건가요?","JPN":"あなたもかかってきますか？","ENG":"Are you going to come at me, too?","TWN":"你也想試試看嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BULLY_NPC_NULL_F","text":{"KOREA":"쳇… 내가 너 얼굴 봐뒀다! 두고 보라고!","JPN":"ちっ……その顔、はっきり覚えたから！　覚えてろ！","ENG":"Bah, I'm going to remember your face! You'd better watch out!","TWN":"嘖…我記住你的臉了，走著瞧！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"나 참… 도시는 저런 한심한 죄인들이 왜 이렇게 많은 거죠?","JPN":"まったく、都市にはあんな情けない罪人たちが多すぎますね。","ENG":"Geez, how come the city is filled with so many pathetic sinners?","TWN":"真是的…為什麼都市裡會有這麼多討厭的罪犯呢？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"자, 지갑 받아요.","JPN":"さあ、モモのお財布ですよ。","ENG":"Here, take your purse.","TWN":"拿去吧，你的錢包。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"오오… 역시 이 몸의 하수인이로다! 훌륭하구나!","JPN":"おお……さすが吾輩の下僕だぞ！　お見事だ！","ENG":"Ooo, I'm so proud of you, my subject! Good job!","TWN":"哇喔…真不愧是本王的手下！你好棒棒！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그리고 하수인이라고 부르지 말아 줄래요?","JPN":"あと、下僕呼ばわりはやめてもらえますか？","ENG":"And could you stop calling me your subject?","TWN":"你可以不要再叫我手下嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"음. 넌 이 몸에게 걸맞은 사천왕의 자격을 충분히 입증했도다.","JPN":"うむ。お前は吾輩にふさわしい四天王の資格を十分示してくれた。","ENG":"Mm... Actually, you've proved your worthiness to be one of my Four Champions.","TWN":"嗯，你已經證明，你有資格成為本王的四天王。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"지금부터는 이름으로 불러주마, 니콜이여. 영광으로 알도록.","JPN":"これからは名前で呼んでやろう、ニコルよ。光栄に思え。","ENG":"From now on, I'll call you by your name, Nicole. You should be honored.","TWN":"從現在起，本王就直接叫你的名字吧！妮可，這可是你的榮耀！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哈……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"뭐, 하수인보다는 낫네요.","JPN":"まあ、下僕よりはマシですね。","ENG":"Well, I guess that's better than a subject.","TWN":"好吧，總之比手下好。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그래서, 가게 일도 다 내팽개치고 나가서 불량배들이랑 한바탕 싸우고 온 거야?","JPN":"で、お店のことはほったらかしにして、不良と喧嘩してきたの？","ENG":"So, you threw away everything here and went out to fight those thugs?","TWN":"意思是你扔下店裡的事不管，跑出去教訓小混混嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으음, 죄송해요.","JPN":"うう、ごめんなさい。","ENG":"Mm, sorry.","TWN":"是的，對不起！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"푸훗!","JPN":"ぷっ！","ENG":"Poof!","TWN":"哈哈！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"L51_1"},"R":null}}}]`);export{e as default};